import React from 'react';
import './App.css';
import { BrowserRouter as Router, Routes, Route, Outlet, Link } from 'react-router-dom';

import Auth from './components/Auth';
import Login from './Login';
import Signup from './Signup';
import Dashboard from './Dashboard';
import CreateProblem from './CreateProblem';
import Problem from './Problem';
import ProblemList from './ProblemList';

// Layout component for common layout (header/nav/footer)
function Layout() {
  return (
    <div>
      <header style={{ padding: '10px', backgroundColor: '#eee' }}>
        <nav>
          <Link to="/dashboard" style={{ marginRight: 10 }}>Dashboard</Link>
          <Link to="/problems" style={{ marginRight: 10 }}>Problems</Link>
          <Link to="/create-problem">Create Problem</Link>
        </nav>
      </header>

      <main style={{ padding: '20px' }}>
        <Outlet /> {/* Render matched child route */}
      </main>

      <footer style={{ padding: '10px', backgroundColor: '#eee', marginTop: '20px' }}>
        &copy; 2025 My Math App
      </footer>
    </div>
  );
}

function App() {
  return (
    <Router>
      <div className="App">
        <Routes>
          {/* Public routes without layout */}
          <Route path="/" element={<Auth />} />
          <Route path="/login" element={<Login />} />
          <Route path="/signup" element={<Signup />} />

          {/* Routes with common layout */}
          <Route element={<Layout />}>
            <Route path="/dashboard" element={<Dashboard />} />
            <Route path="/problems" element={<ProblemList />} />
            <Route path="/problems/:id" element={<Problem />} />
            <Route path="/create-problem" element={<CreateProblem />} />
          </Route>
        </Routes>
      </div>
    </Router>
  );
}

export default App;
